const query = $input.first().json.query || {};

function brl(val) {
  const p = parseFloat(val).toFixed(2).split('.');
  p[0] = p[0].replace(/\B(?=(\d{3})+(?!\d))/g, '.');
  return 'R$ ' + p[0] + ',' + p[1];
}

// ── Modo registro: gera token curto e armazena ──
if (query.action === 'reg') {
  const staticData = $getWorkflowStaticData('global');
  if (!staticData.tokens) staticData.tokens = {};

  // Limpa tokens expirados
  const now = Date.now();
  for (const k of Object.keys(staticData.tokens)) {
    if (now - staticData.tokens[k].ts > 3600000) delete staticData.tokens[k];
  }

  // Token curto de 8 chars (evita chars ambíguos 0/O/1/l)
  const chars = 'ABCDEFGHJKMNPQRSTUVWXYZabcdefghjkmnpqrstuvwxyz23456789';
  let token = '';
  for (let i = 0; i < 8; i++) token += chars[Math.floor(Math.random() * chars.length)];

  staticData.tokens[token] = {
    pixCode: decodeURIComponent(query.code || ''),
    valor: decodeURIComponent(query.valor || ''),
    ts: now
  };

  const url = 'https://purg.com.br/pix?t=' + token;
  return [{ json: { html: JSON.stringify({ url }) } }];
}

// ── Modo visualização: serve o HTML ──
const { t } = query;
const staticData = $getWorkflowStaticData('global');
const tokens = staticData.tokens || {};
const entry = tokens[t];
const now = Date.now();
const expired = !t || !entry || (now - entry.ts) > 3600000;

if (entry && expired) { delete tokens[t]; }

function expiredHtml() {
  return '<!DOCTYPE html><html lang="pt-BR"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Link Expirado - Purg</title><style>*{box-sizing:border-box;margin:0;padding:0}body{background:#f5f7fa;font-family:-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif;min-height:100vh;display:flex;align-items:center;justify-content:center;padding:20px}.card{background:white;border-radius:16px;padding:40px 24px;max-width:420px;width:100%;text-align:center;box-shadow:0 2px 12px rgba(0,0,0,.08)}.logo{margin-bottom:28px}.icon{font-size:48px;margin-bottom:16px}h2{color:#1a1a2a;font-size:22px;margin-bottom:12px}p{color:#787887;font-size:15px;line-height:1.6}</style></head><body><div class="card"><div class="logo"><img src="https://www.purg.com.br/assets/src/assets/logo.2033a3fd6c7c7bd26bf006ec11311890.png" style="width:90%;max-width:510px"></div><div class="icon">⏱️</div><h2>Link expirado</h2><p>Este link de pagamento Pix expirou.<br><br>Se precisar, solicite um novo código pelo WhatsApp.</p></div></body></html>';
}

function pixHtml(valor, pixCode) {
  const vf = brl(valor);
  return '<!DOCTYPE html><html lang="pt-BR"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Pix - Purg</title><style>*{box-sizing:border-box;margin:0;padding:0}body{background:#f5f7fa;font-family:-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif;min-height:100vh;padding:24px 16px}.logo{text-align:center;margin-bottom:24px}.card{background:white;border-radius:16px;padding:28px 20px;max-width:480px;margin:0 auto;box-shadow:0 2px 12px rgba(0,0,0,.08)}.lbl{font-size:11px;font-weight:700;color:#787887;text-transform:uppercase;letter-spacing:.5px;margin-bottom:6px}.lbl-center{text-align:center}.val{font-size:36px;font-weight:800;color:#48C774;margin-bottom:24px;text-align:center}.div{height:1px;background:#e8eaf0;margin-bottom:20px}.code-lbl{font-size:11px;font-weight:700;color:#787887;text-transform:uppercase;letter-spacing:.5px;margin-bottom:14px}.code{border:1.5px solid #dde0ea;border-radius:10px;padding:16px;word-break:break-all;font-family:"Courier New",monospace;font-size:14px;color:#1a1a2a;line-height:1.7;margin-bottom:16px;-webkit-user-select:all;user-select:all}.btn{width:100%;padding:18px;background:#48C774;color:white;border:none;border-radius:12px;font-size:16px;font-weight:700;cursor:pointer}.btn.ok{background:#2d9b52}.tip{text-align:center;color:#a0a3b1;font-size:12px;margin-top:22px}</style></head><body>'
    + '<div class="logo"><img src="https://www.purg.com.br/assets/src/assets/logo.2033a3fd6c7c7bd26bf006ec11311890.png" style="width:90%;max-width:510px"></div>'
    + '<div class="card">'
    + '<div class="lbl lbl-center">Depósito Pix no valor de:</div>'
    + '<div class="val">' + vf + '</div>'
    + '<div class="div"></div>'
    + '<div class="code-lbl">Copie o código abaixo e faça o Pix no seu banco:</div>'
    + '<div class="code" id="code">' + pixCode + '</div>'
    + '<button class="btn" id="btn" onclick="cp()">Copiar código Pix</button>'
    + '<div class="tip" id="tip">Toque no botão para copiar</div>'
    + '</div>'
    + '<script>function cp(){var code=document.getElementById("code").innerText,btn=document.getElementById("btn"),tip=document.getElementById("tip");if(navigator.clipboard&&navigator.clipboard.writeText){navigator.clipboard.writeText(code).then(function(){btn.textContent="✓ Copiado!";btn.classList.add("ok");tip.textContent="Código copiado! Cole no app do seu banco.";}).catch(function(){fb(code,btn,tip)});}else{fb(code,btn,tip);}}function fb(code,btn,tip){var ta=document.createElement("textarea");ta.value=code;ta.style.cssText="position:fixed;opacity:0";document.body.appendChild(ta);ta.focus();ta.select();try{document.execCommand("copy");btn.textContent="✓ Copiado!";btn.classList.add("ok");tip.textContent="Código copiado! Cole no app do seu banco.";}catch(e){tip.textContent="Selecione o código acima e copie manualmente.";}document.body.removeChild(ta);}<\/script>'
    + '</body></html>';
}

const html = expired ? expiredHtml() : pixHtml(entry.valor, entry.pixCode);
return [{ json: { html } }];

